import React, { useCallback, useRef, useState } from 'react';
import { Layer, Line, Stage } from 'react-konva';
import './App.css';
import Toolbar from './components/Toolbar';

const CANVAS_SIZE = 10000; // Large virtual canvas size

function App() {
  const [tool, setTool] = useState('pen');
  const [lines, setLines] = useState([]);
  const [isDrawing, setIsDrawing] = useState(false);
  const stageRef = useRef();
  const [stagePos, setStagePos] = useState({ x: 0, y: 0 });
  const [stageScale, setStageScale] = useState(1);

  const handleMouseDown = useCallback((e) => {
    if (tool !== 'pen') return;

    setIsDrawing(true);
    const pos = e.target.getStage().getPointerPosition();
    const relativePos = {
      x: (pos.x - stagePos.x) / stageScale,
      y: (pos.y - stagePos.y) / stageScale,
    };

    setLines([...lines, {
      id: Date.now(),
      points: [relativePos.x, relativePos.y],
      stroke: '#000000',
      strokeWidth: 2,
    }]);
  }, [tool, lines, stagePos, stageScale]);

  const handleMouseMove = useCallback((e) => {
    if (!isDrawing || tool !== 'pen') return;

    const stage = e.target.getStage();
    const point = stage.getPointerPosition();
    const relativePos = {
      x: (point.x - stagePos.x) / stageScale,
      y: (point.y - stagePos.y) / stageScale,
    };

    setLines((prevLines) => {
      const newLines = [...prevLines];
      const lastLine = newLines[newLines.length - 1];

      if (lastLine) {
        // Add new point to the current line
        lastLine.points = [...lastLine.points, relativePos.x, relativePos.y];
      }

      return newLines;
    });
  }, [isDrawing, tool, stagePos, stageScale]);

  const handleMouseUp = useCallback(() => {
    setIsDrawing(false);
  }, []);

  const handleWheel = useCallback((e) => {
    e.evt.preventDefault();

    const stage = stageRef.current;
    const oldScale = stage.scaleX();
    const pointer = stage.getPointerPosition();

    const mousePointTo = {
      x: (pointer.x - stage.x()) / oldScale,
      y: (pointer.y - stage.y()) / oldScale,
    };

    const newScale = e.evt.deltaY > 0 ? oldScale * 0.9 : oldScale * 1.1;

    const newPos = {
      x: pointer.x - mousePointTo.x * newScale,
      y: pointer.y - mousePointTo.y * newScale,
    };

    setStageScale(newScale);
    setStagePos(newPos);
  }, []);

  // Handle touch events for tablets
  const handleTouchStart = useCallback((e) => {
    if (e.evt.touches && e.evt.touches.length === 1) {
      // Single touch - start drawing
      handleMouseDown(e);
    }
  }, [handleMouseDown]);

  const handleTouchMove = useCallback((e) => {
    e.evt.preventDefault();

    if (e.evt.touches && e.evt.touches.length === 2) {
      // Two finger pinch to zoom
      const touch1 = e.evt.touches[0];
      const touch2 = e.evt.touches[1];

      const dist = Math.sqrt(
        Math.pow(touch2.clientX - touch1.clientX, 2) +
        Math.pow(touch2.clientY - touch1.clientY, 2)
      );

      if (!stageRef.current.lastDist) {
        stageRef.current.lastDist = dist;
        return;
      }

      const scale = stageScale * (dist / stageRef.current.lastDist);
      setStageScale(Math.max(0.1, Math.min(5, scale)));
      stageRef.current.lastDist = dist;
    } else if (e.evt.touches && e.evt.touches.length === 1) {
      // Single touch - continue drawing
      handleMouseMove(e);
    }
  }, [handleMouseMove, stageScale]);

  const handleTouchEnd = useCallback((e) => {
    stageRef.current.lastDist = 0;
    handleMouseUp();
  }, [handleMouseUp]);

  return (
    <div className="app">
      <Toolbar 
        activeTool={tool} 
        onToolChange={setTool}
      />
      <div className="canvas-container">
        <Stage
          ref={stageRef}
          width={window.innerWidth}
          height={window.innerHeight}
          onMouseDown={handleMouseDown}
          onMousemove={handleMouseMove}
          onMouseup={handleMouseUp}
          onTouchStart={handleTouchStart}
          onTouchMove={handleTouchMove}
          onTouchEnd={handleTouchEnd}
          onWheel={handleWheel}
          scaleX={stageScale}
          scaleY={stageScale}
          x={stagePos.x}
          y={stagePos.y}
          draggable={tool === 'pan' || !isDrawing}
        >
          <Layer>
            {lines.map((line) => (
              <Line
                key={line.id}
                points={line.points}
                stroke={line.stroke}
                strokeWidth={line.strokeWidth}
                tension={0.5}
                lineCap="round"
                lineJoin="round"
                globalCompositeOperation="source-over"
              />
            ))}
          </Layer>
        </Stage>
      </div>
    </div>
  );
}

export default App;
